sql:
SELECT plan_name
FROM vps_plans
WHERE is_promo = 1;

SELECT AVG(price) AS average_price
FROM vps_plans
WHERE availability = 1;

SELECT MAX(max_bandwidth) AS max_bandwidth_limit
FROM vps_plans
WHERE availability = 1;

external_knowledge:
- 'Active subscriptions' refers to subscriptions where the status is 'active'; 
- 'Completed payments' refers to billing records where the payment status is 'completed'; 
- 'Last checked within the last 30 days' refers to the last resource check timestamp being greater than or equal to 30 days before the current date.
